// Libera a trava de busy quando a leitura Modbus completou com sucesso
// Aqui você também pode enviar msg para um decoder genérico de PAC3100

flow.set('pac_busy', false);

// Se quiser, pode apenas repassar a msg para um outro nó (decode)
// por enquanto vamos só devolver a msg para seguir no fluxo
return msg;

// Esse nó trata a SAÍDA 2 do modbus-flex-getter
// que na verdade é mais "status" do que "erro"

// Se houver info de erro de verdade:
if (msg.error || (msg.payload && msg.payload.error)) {
    node.warn(
        'Erro Modbus PAC3100: ' + (msg.error || msg.payload.error)
    );
}

// De qualquer forma, libera o "busy"
flow.set('pac_busy', false);

// Não precisa mandar nada adiante
return null;

// HB — Último dado coletado (versão simples pro scanner PAC3100)
// Qualquer resposta OK do Modbus atualiza o timestamp

flow.set('last_modbus_sample_ts', Date.now());
flow.set('last_modbus_sample', msg); // guarda a msg inteira pra diagnóstico se quiser

// Devolve a msg pra seguir para o debug_ok
return msg;

const THRESH = 10000; // 8 s
const COOLDOWN = 10000; // evita tiros em sequência

const now = Date.now();
const last = flow.get('last_modbus_sample_ts') || 0;
const lastKick = flow.get('last_modbus_kick_ts') || 0;
const idle = now - last;

node.status({
  fill: idle > THRESH ? 'red' : 'green',
  shape: 'dot',
  text: `idle ${Math.round(idle / 1000)}s`
});

if (idle > THRESH && (now - lastKick) > COOLDOWN) {
  flow.set('last_modbus_kick_ts', now);
  // dispara o início da cadeia (seu delay de 200 ms leva até Corrente L1)
  return { payload: 'watchdog-kick' };
}

return null;

// Lê o snapshot consolidado
const all = global.get('pac3100_allValues') || {};

// Pode estar como chave numérica (1) ou string ("1")
const pac1 = all[1] || all["1"];

if (!pac1) {
    // Ainda não tem nada do PAC 1
    msg.payload = {
        info: "Sem dados para PAC 1 ainda",
        pacs_disponiveis: Object.keys(all)
    };
} else {
    // Manda só os valores do PAC 1
    msg.payload = pac1;
}

return msg;

