    "CorrenteL3Min",

    "CorrenteL1Max",
    "CorrenteL2Max",
    "CorrenteL3Max",

    "PotenciaAtivaTotal",
    "PotenciaAtivaTotalMax",
    "PotenciaAtivaTotalMin",
    "FatorPotenciaTotal",
    "PotenciaAtivaMaxPeriodo"
    // adiciona aqui o que mais precisar
];

// Objeto de origem: vem do function anterior ("Get PACx allValues")
const src = msg.payload || {};
const filtered = {};

// 1) Timestamp
filtered.DateTime = new Date();    // Date nativo (Mongo grava como ISODate)

// 2) Copia apenas os campos que interessam
for (const campo of CAMPOS) {
    if (Object.prototype.hasOwnProperty.call(src, campo)) {
        filtered[campo] = src[campo];
    }
}

// 3) unitid (pode vir no msg ou dentro do próprio payload)
const unitid = msg.unitid !== undefined ? msg.unitid : src.unitid;

if (unitid !== undefined) {
    filtered.unitid = unitid;
    filtered.IDMaq = EQUIP_MAP[unitid] || `UNIT_${unitid}`;
} else {
    // fallback, se por algum motivo não vier unitid
    filtered.IDMaq = "SE03_MM01";
}

// 🔹 Garante que a mensagem para o Mongo tenha APENAS o documento no payload
// (sem topic, sem contadores, sem desvios etc.)
return {
    payload: [filtered],
    operation: "insertOne"
};

