// PAC3100 decode – inst., máximos, mínimos e energia
// Usa o mapa de registradores do manual (tabela A.2.5)
// - floats: 2 words (32 bits, big-endian)
// - doubles de energia: 4 words (64 bits, big-endian)

"use strict";

// 1) Pega o array de words (16 bits) vindo do Modbus
let words = null;

if (msg.responseBuffer && Array.isArray(msg.responseBuffer.data)) {
    words = msg.responseBuffer.data;
} else if (Array.isArray(msg.payload)) {
    words = msg.payload;
}

if (!words) {
    node.warn("PAC3100 decode: nenhum array de words encontrado em msg.responseBuffer.data ou msg.payload");
    return msg;
}

const startAddr = (msg.modbusRequest && Number.isInteger(msg.modbusRequest.address))
    ? msg.modbusRequest.address
    : 1;

const qty = words.length;
const endAddr = startAddr + qty - 1;

// 2) Helpers para leitura dos tipos

function readFloat(offset) {
    // offset = número de registrador Modbus (1, 3, 5, ..., 127, 801, etc)
    const idx = offset - startAddr; // posição relativa no array de words
    if (idx < 0 || (idx + 1) >= qty) return null;

    const buf = Buffer.alloc(4);
    buf.writeUInt16BE(words[idx], 0);
    buf.writeUInt16BE(words[idx + 1], 2);
    return buf.readFloatBE(0);
}

function readDouble(offset) {
    const idx = offset - startAddr;
    if (idx < 0 || (idx + 3) >= qty) return null;

    const buf = Buffer.alloc(8);
    buf.writeUInt16BE(words[idx], 0);
    buf.writeUInt16BE(words[idx + 1], 2);
    buf.writeUInt16BE(words[idx + 2], 4);
    buf.writeUInt16BE(words[idx + 3], 6);
    return buf.readDoubleBE(0);
}

