// 4) Decodifica só o que está dentro do intervalo [startAddr .. endAddr]

const decoded = {};
const values = {};

for (const [key, def] of Object.entries(PAC3100_REGS)) {
    if (def.offset < startAddr || (def.offset + def.words - 1) > endAddr) {
        continue; // este registrador não veio neste telegrama
    }

    let v = null;
    if (def.type === "float") {
        v = readFloat(def.offset);
    } else if (def.type === "double") {
        v = readDouble(def.offset);
    }

    if (v === null || Number.isNaN(v)) continue;

    decoded[key] = {
        offset: def.offset,
        words: def.words,
        type: def.type,
        name: def.name,
        unit: def.unit,
        value: v
    };

    values[key] = v;
}

// 5) Atualiza estado no msg e no flow (para ter todas as grandezas juntas)

msg.pac3100 = msg.pac3100 || {};

const unitid = (msg.modbusRequest && msg.modbusRequest.unitid) ||
    msg.unitId || 1;

msg.pac3100.unitid = unitid;
msg.pac3100.start = startAddr;
msg.pac3100.quantity = qty;
msg.pac3100.decoded = decoded;
msg.pac3100.values = values;

// Acumula todas as grandezas por unitid em flow context
let all = global.get("pac3100_allValues") || {};
all[unitid] = Object.assign({}, all[unitid] || {}, values);
global.set("pac3100_allValues", all);

// Versão consolidada (tudo que já foi lido deste PAC)
msg.pac3100.allValues = all[unitid] || {};

return msg;

// Scheduler simples para PAC3100
// - Varre multimedidores (unitid em PACS)
// - Varre 4 blocos de registradores por PAC
// - Usa global.state_pac para lembrar onde parou
// - Mostra status com contador de requisições (com separador de milhar)

// Quais PACs existem na rede?
const PACS = [1, 2, 3, 4, 5, 6, 7];  // unitids disponíveis

// Quais blocos de registradores queremos ler?
const BLOCS = [
    { name: "fast_1", adr: 1, qty: 54 },  // offsets 1..54
    { name: "fast_2", adr: 55, qty: 54 },  // offsets 55..108
    { name: "fast_3", adr: 109, qty: 54 },  // offsets 109..162
    { name: "demand", adr: 501, qty: 20 },  // offsets 501..521 
    { name: "energy", adr: 801, qty: 4 }    // energia total
];

// Estado atual da varredura (lido do globalo)
let state = global.get("state_pac") || {
    pacIndex: 0,   // índice em PACS
    blocIndex: 0   // índice em BLOCS
};

// Contador de requisições (total desde que o fluxo subiu)
let reqCount = global.get("pac_req_count") || 0;
reqCount++;
global.set("pac_req_count", reqCount);

// Escolhe o PAC e o bloco atuais
const currentPac = PACS[state.pacIndex];
const currentBloc = BLOCS[state.blocIndex];

// Formata contador com separador de milhar
const reqStr = reqCount.toLocaleString('pt-BR');  // ex: 1.234, 12.345

// Atualiza status do nó (balãozinho cinza)
node.status({
    fill: "grey",
    shape: "dot",
    text: `req #${reqStr} | PAC ${currentPac} | ${currentBloc.name}`
});

// Avança estado para a PRÓXIMA chamada
state.blocIndex++;
if (state.blocIndex >= BLOCS.length) {
    state.blocIndex = 0;
    state.pacIndex++;
    if (state.pacIndex >= PACS.length) {
        state.pacIndex = 0;
    }
}
global.set("state_pac", state);

// Monta requisição Modbus para o PAC3100
msg.payload = {
    fc: 3,                 // Holding Registers
    unitid: currentPac,        // PAC atual
    address: currentBloc.adr,   // endereço inicial do bloco
    quantity: currentBloc.qty   // quantidade de registradores
};

// Metadados só pra debug / tratamento depois
msg.pac3100 = {
    unitid: currentPac,
    block: currentBloc.name,
    adr: currentBloc.adr,
    qty: currentBloc.qty
};

return msg;

// Consumo de energia MM01 a cada 15 min (usa snapshot do PAC3100 em flow)

