if (!pac1 || !Number.isFinite(pac1.EnergiaAtivaTotal)) {
    node.warn("Sem EnergiaAtivaTotal válida para PAC 1 (SE03_MM01).");
    return null;
}

// Timestamp desta amostragem (15 min)
const now = new Date();

// Contador bruto em Wh do PAC3100 (double que veio do decoder)
const energiaAtualWh = Number(pac1.EnergiaAtivaTotal);

// 2) Recupera última leitura salva para MM01 (só deste fluxo 15min)
const keyPrev = "mm01_prev_wh_15min";
const prevWh = flow.get(keyPrev);

let deltaWh = null;
let reset = false;

if (Number.isFinite(prevWh)) {
    deltaWh = energiaAtualWh - prevWh;

    // Se ficou negativo, contador voltou (reset/overflow/troca de medidor)
    if (deltaWh < 0) {
        deltaWh = 0;
        reset = true;
    }
}

// Atualiza memória para próxima execução (daqui 15 min)
flow.set(keyPrev, energiaAtualWh);

// 3) Monta documento para Mongo
const doc = {
    DateTime: now,                            // BSON Date no Mongo
    IDMaq: "SE03_MM01",                       // identifica a máquina
                             // PAC 1

    // Contador total (Wh)
    wh_total: Math.round(energiaAtualWh),

    // Consumo no intervalo de 15 min (kWh)
    kwh_intervalo: deltaWh == null ? null : (deltaWh / 1000),

    // Flag de reset de contador
    reset_flag: reset,


};

// 4) Prepara para o mongodb4
msg.payload = [doc];          // insertOne espera array
msg.operation = "insertOne";  // como no fluxo antigo

