// NÓ: Pausa P/ Reset Valores  (v2 – multi-pausa com tratamento)
// Pré-requisito: msg.pausa_id definido pelo nó 'Set PausaXX'
// ═══════════════════════════════════════════════════════════════

const PAUSAS_VALIDAS = [
    'pausa01','pausa02','pausa03','pausa04','pausa05',
    'pausa06','pausa07','pausa08','pausa09','pausa10'
];

// ── 1. Lê pausa_id da mensagem ──────────────────────────────────
const pausa_id = msg.pausa_id;

if (!pausa_id) {
    node.error('pausa_id não definido! Conecte um nó "Set PausaXX" antes deste.', msg);
    node.status({ fill:'red', shape:'ring', text:'ERRO: pausa_id ausente' });
    return null;
}

if (!PAUSAS_VALIDAS.includes(pausa_id)) {
    node.error(`pausa_id inválido: "${pausa_id}". Valores aceitos: ${PAUSAS_VALIDAS.join(', ')}`, msg);
    node.status({ fill:'red', shape:'ring', text:`ERRO: "${pausa_id}" inválido` });
    return null;
}

// ── 2. Verifica conflito com pausa já ativa ──────────────────────
const reset_flag   = flow.get('reset_flag')   || false;
const active_pause = flow.get('active_pause') || null;

if (reset_flag && active_pause) {
    if (active_pause === pausa_id) {
        // Mesma pausa solicitada duas vezes
        node.warn(`"${pausa_id}" já está ativa. Solicitação ignorada.`, msg);
        node.status({ fill:'yellow', shape:'ring', text:`AVISO: ${pausa_id} já ativa` });
    } else {
        // Pausa diferente solicitada enquanto outra está ativa
        node.error(
            `CONFLITO: "${active_pause}" está ativa. ` +
            `Encerre-a antes de iniciar "${pausa_id}".`, msg
        );
        node.status({ fill:'red', shape:'dot', text:`CONFLITO: ${active_pause} ✕ ${pausa_id}` });
    }
    return null;   // ← descarta a mensagem, não altera o contexto
}

// ── 3. Ativa a pausa ────────────────────────────────────────────
flow.set('reset_flag',   true);
flow.set('active_pause', pausa_id);

const agora       = new Date();
const ts_data_hora = agora.toLocaleString('pt-BR');
const ts_hora      = agora.toLocaleTimeString('pt-BR', { hour12: false });

msg.reset_flag   = true;
msg.active_pause = pausa_id;
msg.payload = {
    flag:       'reset_flag',
    value:      true,
    pausa_id:   pausa_id,
    texto:      `reset_flag = true | ${pausa_id} ativada`,
    timestamp:  ts_data_hora
};

node.status({ fill:'yellow', shape:'dot', text:`${pausa_id} ativa @ ${ts_hora}` });

return msg;

// ═══════════════════════════════════════════════════════════════
// NÓ: Pausa de Loop – Reset TRUE  (v2 – 11 saídas)
//
// Saída  1 → fluxo normal (nenhuma pausa ativa)
// Saída  2 → pausa01
// Saída  3 → pausa02
//   …
// Saída 11 → pausa10
// ═══════════════════════════════════════════════════════════════

const TOTAL_SAIDAS = 11;  // 1 normal + 10 pausas

const PAUSA_MAP = {
    'pausa01':  1,
    'pausa02':  2,
    'pausa03':  3,
    'pausa04':  4,
    'pausa05':  5,
    'pausa06':  6,
    'pausa07':  7,
    'pausa08':  8,
    'pausa09':  9,
    'pausa10': 10
};

// ── Lê contexto ────────────────────────────────────────────────
const reset_flag   = flow.get('reset_flag')   || false;
const active_pause = flow.get('active_pause') || null;

msg.reset_flag   = reset_flag;
msg.active_pause = active_pause;

// Prepara array de saídas (todas nulas por padrão)
const outputs = new Array(TOTAL_SAIDAS).fill(null);

// ── Caso 1: Nenhuma pausa ativa → Saída 1 (fluxo normal) ───────
if (!reset_flag || !active_pause) {
    node.status({ fill:'green', shape:'dot', text:'Normal → saída 1' });
    outputs[0] = msg;
    return outputs;
}

// ── Caso 2: Pausa ativa – roteia para a saída correspondente ────
const saida_idx = PAUSA_MAP[active_pause];

if (saida_idx === undefined) {
    // active_pause tem valor inesperado (contexto corrompido?)
    node.error(
        `active_pause desconhecido: "${active_pause}". ` +
        `Verifique o contexto de fluxo (flow.active_pause).`, msg
    );
    node.status({ fill:'red', shape:'ring', text:`ERRO: pausa inválida (${active_pause})` });
    return null;
}

node.status({
    fill:  'yellow',
    shape: 'dot',
    text:  `${active_pause} → saída ${saida_idx + 1}`
});

outputs[saida_idx] = msg;
return outputs;

