// NÓ: Reset – Encerra Pausa  (v2)
// Limpa reset_flag E active_pause do contexto de fluxo.
// Conectar na saída de CADA pausa após ela concluir.
// ═══════════════════════════════════════════════════════════════

const active_pause = flow.get('active_pause') || 'nenhuma';

flow.set('reset_flag',   false);
flow.set('active_pause', null);

const agora        = new Date();
const ts_data_hora = agora.toLocaleString('pt-BR');
const ts_hora      = agora.toLocaleTimeString('pt-BR', { hour12: false });

msg.reset_flag   = false;
msg.active_pause = null;
msg.payload = {
    flag:             'reset_flag',
    value:            false,
    pausa_encerrada:  active_pause,
    texto:            `reset_flag = false | ${active_pause} encerrada`,
    timestamp:        ts_data_hora
};

node.status({ fill:'green', shape:'dot', text:`${active_pause} encerrada @ ${ts_hora}` });

return msg;

"use strict";

// ====== CONFIG ======
const PACS       = [1, 2, 3, 4, 5, 6, 7];
const periodMin  = 15;
const syncViaBus = 1;

// ====== HELPER ======
function u32ToRegsBE(u32) {
    return [(u32 >>> 16) & 0xFFFF, u32 & 0xFFFF];
}

// ====== ESTADO ======
let state = global.get("state_pac_write") || { pacIndex: 0 };

// ── Se entrada "reset" → volta ao pac1 antes de tudo ──────────
if (msg.topic === "reset") {
    state.pacIndex = 0;
    global.set("state_pac_write", state);
}

let reqCount = global.get("pac_write_req_count") || 0;
reqCount++;
global.set("pac_write_req_count", reqCount);

const currentPac = PACS[state.pacIndex];
const isLast     = state.pacIndex === PACS.length - 1;

// ====== STATUS ======
const reqStr = reqCount.toLocaleString('pt-BR');
const modeLabel = msg.topic === "reset" ? " ↺ reset" : "";
node.status({
    fill:  isLast ? "blue" : "grey",
    shape: "dot",
    text:  `req #${reqStr} | PAC ${currentPac}${isLast ? " ★ último" : ""}${modeLabel}`
});

// ====== AVANÇA ESTADO ======
state.pacIndex++;
if (state.pacIndex >= PACS.length) {
    state.pacIndex = 0;
}
global.set("state_pac_write", state);

// ====== MONTA MENSAGENS DE ESCRITA ======
const msgs = [];

msgs.push({
    payload: {
        fc: 16,
        unitid: currentPac,
        address: 50021,
        quantity: 2,
        value: u32ToRegsBE(periodMin)
    },
    topic: `write_50021_unit${currentPac}`
});

msgs.push({
    payload: {
        fc: 16,
        unitid: currentPac,
        address: 50023,
        quantity: 2,
        value: u32ToRegsBE(syncViaBus)
    },
    topic: `write_50023_unit${currentPac}`
});

msgs.push({
    payload: {
        fc: 6,
        unitid: currentPac,
        address: 60005,
        quantity: 1,
        value: periodMin
    },
    topic: `write_60005_unit${currentPac}`
});

// ====== SAÍDAS ======
let out2 = null;

if (isLast) {
    setTimeout(() => {
        flow.set("pac_write_concluido", true);
        node.send([null, { payload: true, topic: "write_concluido" }]);
    }, 500);
} else {
    flow.set("pac_write_concluido", false);
}

return [msgs, out2];

