const DEBOUNCE_MS = 90 * 1000; // 90 segundos

const ultimaExecucao = flow.get("quarto_hora_ultima_exec") || 0;
const agora = Date.now();

if (agora - ultimaExecucao < DEBOUNCE_MS) {
    const restante = Math.ceil((DEBOUNCE_MS - (agora - ultimaExecucao)) / 1000);
    node.status({ fill: "grey", shape: "ring", text: `bloqueado — faltam ${restante}s` });
    return null;
}

const minutos = new Date().getMinutes();
const quartosDeHora = [0, 15, 30, 45];

if (quartosDeHora.includes(minutos)) {
    flow.set("quarto_hora_ultima_exec", agora);
    node.status({ fill: "green", shape: "dot", text: `✓ ${minutos}min → saída acionada` });
    return msg;
}

node.status({ fill: "grey", shape: "ring", text: `${minutos}min → aguardando quarto de hora` });
return null;

"use strict";

// ====== CONFIG ======
const PACS = [1, 2, 3, 4, 5, 6, 7];

// ====== ESTADO ======
let state = global.get("state_pac_read_setup") || { pacIndex: 0 };

if (msg.topic === "reset") {
    state.pacIndex = 0;
    global.set("state_pac_read_setup", state);
}

let reqCount = global.get("pac_read_setup_req_count") || 0;
reqCount++;
global.set("pac_read_setup_req_count", reqCount);

const currentPac = PACS[state.pacIndex];
const isLast     = state.pacIndex === PACS.length - 1;

// ====== STATUS ======
const reqStr = reqCount.toLocaleString('pt-BR');
const modeLabel = msg.topic === "reset" ? " ↺ reset" : "";
node.status({
    fill:  isLast ? "blue" : "grey",
    shape: "dot",
    text:  `req #${reqStr} | PAC ${currentPac}${isLast ? " ★ último" : ""}${modeLabel}`
});

// ====== AVANÇA ESTADO ======
state.pacIndex++;
if (state.pacIndex >= PACS.length) {
    state.pacIndex = 0;
}
global.set("state_pac_read_setup", state);

// ====== MONTA MENSAGEM DE LEITURA ======
// 50021 (2 regs) + 50023 (2 regs) em uma única requisição FC3
// 60005 é write-only, não pode ser lido
const msgs = [];

msgs.push({
    payload: {
        fc: 3,
        unitid: currentPac,
        address: 50021,
        quantity: 4
    },
    topic: `read_50021_50023_unit${currentPac}`,
    pac_setup: {
        unitid: currentPac
    }
});

// ====== SAÍDAS ======
let out2 = null;

if (isLast) {
    setTimeout(() => {
        flow.set("pac_read_setup_concluido", true);
        node.send([null, { payload: true, topic: "read_setup_concluido" }]);
    }, 500);
} else {
    flow.set("pac_read_setup_concluido", false);
}

return [msgs, out2];

